const contactData = $('Extract Contact Data1').first().json;

// Get chat history from PostgreSQL
const historyItems = $input.all();

// Build conversation context
let chatHistory = "";

if (historyItems.length > 0) {
  chatHistory = "\n\n=== PREVIOUS CONVERSATION ===\n";

  historyItems.forEach(item => {
    const msg = item.json;
    const speaker = msg.role === 'user' ? 'Customer' : 'AI Laptopwala';
    chatHistory += `${speaker}: ${msg.content}\n`;
  });

  chatHistory += "=== END OF CONVERSATION ===\n\n";
}

// AI Classification: Detect service vs sales intent
const messageText = contactData.messageText.toLowerCase();

// Service/repair keywords (Hindi, English, Hinglish)
const serviceKeywords = [
  'repair', 'service', 'thik kro', 'thik karo', 'fix', 'kharab', 
  'problem', 'issue', 'warranty claim', 'maintenance', 'servicing',
  'repair karo', 'theek karo', 'kaam nahi kar raha', 'not working',
  'broken', 'damage', 'screen broken', 'keyboard issue', 'battery problem'
];

// Sales keywords (Hindi, English, Hinglish)
const salesKeywords = [
  'buy', 'purchase', 'laptop chahiye', 'desktop chahiye', 'price', 
  'budget', 'kharidna', 'lena hai', 'kitne ka', 'kitne mein',
  'available', 'stock', 'new laptop', 'gaming laptop', 'office laptop',
  'student laptop', 'specifications', 'specs', 'ram', 'storage'
];

// Check for service keywords
const hasServiceKeyword = serviceKeywords.some(keyword => messageText.includes(keyword));

// Check for sales keywords
const hasSalesKeyword = salesKeywords.some(keyword => messageText.includes(keyword));

// Determine category (default to sales if unclear)
let category = 'sales';
if (hasServiceKeyword && !hasSalesKeyword) {
  category = 'services';
} else if (hasServiceKeyword && hasSalesKeyword) {
  // If both present, prioritize based on context
  // For now, default to sales unless service keywords are more prominent
  const serviceCount = serviceKeywords.filter(k => messageText.includes(k)).length;
  const salesCount = salesKeywords.filter(k => messageText.includes(k)).length;
  category = serviceCount > salesCount ? 'services' : 'sales';
}

// Return data with chat history and category
return [{
  json: {
    contactUid: contactData.contactUid,
    firstName: contactData.firstName,
    phoneNumber: contactData.phoneNumber,
    messageText: contactData.messageText,
    phoneNumberId: contactData.phoneNumberId,
    chatHistory: chatHistory,
    category: category
  }
}];

const item = $input.first().json;
const products = item.products || {};
const keys = Object.keys(products);
const output = [];
const productType = item.productType;

// =========================
// 📝 Intro Message
// =========================
if (item.messageText) {
  output.push({
    json: {
      phoneNumberId: item.phoneNumberId,
      phoneNumber: item.phoneNumber,
      messageType: 'text',
      message: item.messageText,
      delaySeconds: 0
    }
  });
}

// =========================
// 🔄 Product Loop
// =========================

keys.forEach((key, productIndex) => {

  const product = products[key];

  const priceRange = product.Price_Range || 'Price on request';
  const stockQty = product.Stock_Quantity ?? 0;

  let urgencyText = '';

  if (stockQty <= 2 && stockQty > 0) {
    urgencyText = '🔥 *Only ' + stockQty + ' left!*\n';
  } else if (stockQty <= 5 && stockQty > 2) {
    urgencyText = '⚡ *' + stockQty + ' units left - Selling fast!*\n';
  }

  // =========================
  // 🎯 Dynamic Caption Builder
  // =========================

  let caption = '';

  // 💻 LAPTOP
  if (productType === 'laptop') {

    caption =
      `*${productIndex + 1}/${keys.length}: ${product.Brand ?? ''} ${product.Model ?? ''}*\n` +
      `${urgencyText}` +
      `\n💰 *₹${priceRange}*\n` +
      `⚡ ${product.Processor ?? 'N/A'} | 🧠 ${product.RAM_GB ?? 'N/A'}GB RAM\n` +
      `💾 ${product.Storage_GB ?? 'N/A'}GB ${product.Storage_Type ?? ''} | 📺 ${product.Screen_Size ?? ''}\n` +
      `🎮 ${product.Graphics ?? 'Integrated'} | ✨ ${product.Condition ?? ''}\n` +
      `🛡️ ${product.Warranty_in_months ?? ''}mo warranty | 🎁 ${product.Special_Feature ?? ''}`;

  }

  // 🖥 DESKTOP (FIXED)
else if (productType === 'desktop') {

  caption =
    `*${productIndex + 1}/${keys.length}: ${product.Brand ?? ''} ${product.Model ?? ''}*\n` +
    `${urgencyText}` +
    `\n💰 *₹${priceRange}*\n` +
    `⚡ ${product.Processor ?? ''} ${product.Generation ?? ''}\n` +
    `🧠 ${product.RAM_GB ?? ''}GB ${product.RAM_Type ?? ''}\n` +
    `💾 ${product.Storage_GB ?? ''}GB\n` +
    `📺 ${product.Monitor_Size ?? ''} inch\n` +
    `✨ ${product.Condition ?? ''}\n` +
    `🛡️ ${product.Warranty_in_months ?? ''}mo warranty\n` +
    `🎁 ${product.Special_Feature ?? ''}`;


  }

  // 🔌 ACCESSORY
  else if (productType === 'accessory') {

    caption =
      `*${productIndex + 1}/${keys.length}: ${product.Accessories_Name ?? ''}*\n` +
      `\n💰 *₹${priceRange}*`;

  }

  // 🧩 Default Safe
  else {
    caption =
      `*${productIndex + 1}/${keys.length}: Product*\n` +
      `💰 ₹${priceRange}`;
  }

  // =========================
  // 📞 Footer
  // =========================

  caption +=
    `\n\n📞 *Order now:* 9893496163\n` +
    `🎁 *Follow for exclusive gifts:*\n` +
    `📸 Instagram: https://www.instagram.com/ailaptopwala/\n` +
    `🎥 YouTube: https://www.youtube.com/@ailaptopwala`;


  // =========================
  // 🖼 IMAGE HANDLING
  // =========================

  const imageUrl1 = product.Image_Url_1;
  const imageUrl2 = product.Image_Url_2;

  const hasImage1 = imageUrl1 && imageUrl1.trim() !== '' && imageUrl1 !== 'null';
  const hasImage2 = imageUrl2 && imageUrl2.trim() !== '' && imageUrl2 !== 'null';

  if (item.showImages && (hasImage1 || hasImage2)) {

    if (hasImage1) {
      output.push({
        json: {
          phoneNumberId: item.phoneNumberId,
          phoneNumber: item.phoneNumber,
          messageType: 'image',
          imageUrl: imageUrl1,
          caption: caption + '\n\n📷 *Image 1*',
          delaySeconds: (productIndex * 3) + 1
        }
      });
    }

    if (hasImage2) {
      output.push({
        json: {
          phoneNumberId: item.phoneNumberId,
          phoneNumber: item.phoneNumber,
          messageType: 'image',
          imageUrl: imageUrl2,
          caption: '📷 *Image 2*',
          delaySeconds: (productIndex * 3) + 2
        }
      });
    }

  } else {

    output.push({
      json: {
        phoneNumberId: item.phoneNumberId,
        phoneNumber: item.phoneNumber,
        messageType: 'text',
        message: caption,
        delaySeconds: (productIndex * 3) + 1
      }
    });

  }

});

return output;

const aiOutput = $input.first().json.output;
const contactData = $('Extract Contact Data1').first().json;

// =========================
// 🧹 CLEAN AI OUTPUT
// =========================
let cleaned = aiOutput;

if (typeof aiOutput === 'string') {
  cleaned = aiOutput
    .replace(/```json/gi, '')
    .replace(/```/g, '')
    .trim();
}

let parsedResponse;

try {

  parsedResponse = JSON.parse(cleaned);

  // =========================
  // 🛡 BASE VALIDATION
  // =========================
  if (!parsedResponse.message) {
    parsedResponse.message = "I found some options for you!";
  }

  if (!parsedResponse.products || typeof parsedResponse.products !== 'object') {
    parsedResponse.products = {};
  }

  if (typeof parsedResponse.showImages !== 'boolean') {
    parsedResponse.showImages = false;
  }

  if (!parsedResponse.productType) {
    parsedResponse.productType = null;
  }

  // =========================
  // 🔥 NORMALIZATION
  // =========================

  if (Object.keys(parsedResponse.products).length > 0) {

    const normalizedProducts = {};
    let imageFound = false;

    Object.keys(parsedResponse.products).forEach(key => {

      const product = parsedResponse.products[key] || {};

      // =====================
      // 💰 PRICE CLEANER
      // =====================
      const rawPrice =
        product.Price_Range ??
        product.price_range ??
        product.price_range_inr ??
        product.price ??
        null;

      let cleanedPrice = null;
      let priceMin = null;
      let priceMax = null;

      if (rawPrice) {
        cleanedPrice = rawPrice.toString().replace(/₹/g, '').trim();
        const split = cleanedPrice.split('-');

        if (split.length === 2) {
          priceMin = parseInt(split[0]);
          priceMax = parseInt(split[1]);
        } else {
          priceMin = parseInt(cleanedPrice);
          priceMax = parseInt(cleanedPrice);
        }
      }

      // =====================
      // 🖼 UNIVERSAL IMAGE FIX
      // =====================
      const image1 = product.Image_Url_1 ?? product.image_url_1 ?? null;
      const image2 = product.Image_Url_2 ?? product.image_url_2 ?? null;

      if (image1 || image2) {
        imageFound = true;
      }

      // =====================
      // 🧠 SMART DEVICE DETECTION
      // =====================
      const hasBrandModel = product.Brand || product.Model;

      // =====================
      // 💻 LAPTOP
      // =====================
      if (parsedResponse.productType === "laptop") {

        normalizedProducts[key] = {
          Brand: product.Brand ?? null,
          Model: product.Model ?? null,
          Processor: product.Processor ?? null,
          RAM_GB: product.RAM_GB ?? null,
          Storage_Type: product.Storage_Type ?? null,
          Storage_GB: product.Storage_GB ?? null,
          Screen_Size: product.Screen_Size ?? product.Monitor_Size ?? null,
          Graphics: product.Graphics ?? null,
          Condition: product.Condition ?? null,
          Stock_Quantity: product.Stock_Quantity ?? null,
          Special_Feature: product.Special_Feature ?? null,
          Warranty_in_months: product.Warranty_in_months ?? null,
          Price_Range: cleanedPrice,
          Price_Min: priceMin,
          Price_Max: priceMax,
          Image_Url_1: image1,
          Image_Url_2: image2
        };

      }

      // =====================
      // 🖥 DESKTOP (FIXED)
      // =====================
      else if (parsedResponse.productType === "desktop") {

        // If AI sent Brand/Model structure → treat like computer device
        if (hasBrandModel) {

          normalizedProducts[key] = {
            Brand: product.Brand ?? null,
            Model: product.Model ?? null,
            Processor: product.Processor ?? null,
            Generation: product.Generation ?? null,
            RAM_GB: product.RAM_GB ?? null,
            RAM_Type: product.RAM_Type ?? null,
            Storage_GB: product.Storage_GB ?? null,
            Monitor_Size: product.Monitor_Size ?? null,
            Graphics: product.Graphics ?? null,
            Condition: product.Condition ?? null,
            Stock_Quantity: product.Stock_Quantity ?? null,
            Special_Feature: product.Special_Feature ?? null,
            Warranty_in_months: product.Warranty_in_months ?? null,
            Price_Range: cleanedPrice,
            Price_Min: priceMin,
            Price_Max: priceMax,
            Image_Url_1: image1,
            Image_Url_2: image2
          };

        } else {

          // Legacy desktop structure fallback
          normalizedProducts[key] = {
            Name: product.name ?? null,
            Processor: product.processor ?? null,
            RAM: product.ram ?? null,
            Storage: product.storage ?? null,
            Monitor_Size: product.monitor ?? null,
            Condition: product.condition ?? null,
            Warranty: product.warranty ?? null,
            Special_Feature: product.special_feature ?? null,
            Stock_Quantity: product.stock_quantity ?? null,
            Price_Range: cleanedPrice,
            Price_Min: priceMin,
            Price_Max: priceMax,
            Image_Url_1: image1,
            Image_Url_2: image2
          };

        }

      }

      // =====================
      // 🔌 ACCESSORY
      // =====================
      else if (parsedResponse.productType === "accessory") {

        normalizedProducts[key] = {
          Accessories_Name: product.accessories_name ?? product.Accessories_Name ?? null,
          Price_Range: cleanedPrice,
          Price_Min: priceMin,
          Price_Max: priceMax,
          Image_Url_1: image1,
          Image_Url_2: image2
        };

      }

      // =====================
      // 🧩 DEFAULT SAFE
      // =====================
      else {

        normalizedProducts[key] = {
          ...product,
          Image_Url_1: image1,
          Image_Url_2: image2
        };

      }

    });

    parsedResponse.products = normalizedProducts;

    if (imageFound) {
      parsedResponse.showImages = true;
    }

  }

} catch (e) {

  console.error('JSON Parse Error:', e);
  console.error('Raw AI Output:', aiOutput);

  return [{
    phoneNumberId: contactData.phoneNumberId,
    phoneNumber: contactData.phoneNumber,
    messageText: "I apologize, I'm having trouble processing that. Could you rephrase your request?",
    hasProducts: false,
    error: true
  }];
}

// =========================
// 📤 FINAL RETURN
// =========================

if (Object.keys(parsedResponse.products).length > 0) {

  return [{
    phoneNumberId: contactData.phoneNumberId,
    phoneNumber: contactData.phoneNumber,
    messageText: parsedResponse.message,
    hasProducts: true,
    showImages: parsedResponse.showImages ?? false,
    productType: parsedResponse.productType ?? null,
    products: parsedResponse.products
  }];

} else {

  return [{
    phoneNumberId: contactData.phoneNumberId,
    phoneNumber: contactData.phoneNumber,
    messageText: parsedResponse.message,
    hasProducts: false,
    showImages: false,
    productType: parsedResponse.productType ?? null
  }];

}

